INSERT INTO `questions` (`id`, `category`, `topic`, `sub_domain`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_answer`, `difficulty`, `discrimination`, `explanation`, `active`, `created_at`) VALUES
(1, 'Quantitative Aptitude', 'Percentages', 'Percentage Calculations', 'If 20% of a number is 60, what is the number?', '200', '300', '400', '500', '300', -1.20, 1.00, '20% = 60, so 100% = 60 × 5 = 300', 1, '2026-03-25 11:50:15'),
(2, 'Quantitative Aptitude', 'Percentages', 'Percentage Change', 'A shirt originally costing $80 is on sale at 25% off. What is the sale price?', '$55', '$60', '$65', '$70', '$60', -0.80, 1.00, '25% of 80 = 20, so 80 - 20 = 60', 1, '2026-03-25 11:50:15'),
(3, 'Quantitative Aptitude', 'Percentages', 'Profit and Loss', 'A trader buys goods for $200 and sells them for $250. What is the profit percentage?', '20%', '25%', '30%', '35%', '25%', -0.50, 1.00, 'Profit = 50, Profit% = (50/200) × 100 = 25%', 1, '2026-03-25 11:50:15'),
(4, 'Quantitative Aptitude', 'Percentages', 'Compound Interest', 'What is the compound interest on $1000 at 10% per annum for 2 years?', '$200', '$210', '$220', '$230', '$210', 0.20, 1.00, 'A = 1000(1.1)² = 1210, CI = 210', 1, '2026-03-25 11:50:15'),
(5, 'Quantitative Aptitude', 'Algebra', 'Linear Equations', 'Solve for x: 2x + 5 = 15', '3', '4', '5', '6', '5', -1.00, 1.00, '2x = 10, x = 5', 1, '2026-03-25 11:50:15'),
(6, 'Quantitative Aptitude', 'Algebra', 'Quadratic Equations', 'What are the roots of x² - 5x + 6 = 0?', '2,3', '1,6', '-2,-3', '2,-3', '2,3', 0.50, 1.00, '(x-2)(x-3)=0, so x=2 or x=3', 1, '2026-03-25 11:50:15'),
(7, 'Quantitative Aptitude', 'Algebra', 'Simultaneous Equations', 'Solve: x + y = 10, x - y = 4', 'x=7,y=3', 'x=6,y=4', 'x=8,y=2', 'x=5,y=5', 'x=7,y=3', 0.80, 1.00, 'Adding equations: 2x=14, x=7, y=3', 1, '2026-03-25 11:50:15'),
(8, 'Quantitative Aptitude', 'Ratios', 'Ratio Problems', 'If a:b = 2:3 and b:c = 4:5, find a:c', '8:15', '2:5', '4:9', '8:12', '8:15', 1.00, 1.00, 'a:b = 2:3 = 8:12, b:c = 4:5 = 12:15, so a:c = 8:15', 1, '2026-03-25 11:50:15'),
(9, 'Quantitative Aptitude', 'Ratios', 'Proportion', 'If 5 workers can complete a job in 12 days, how many days will 10 workers take?', '4 days', '5 days', '6 days', '8 days', '6 days', -0.20, 1.00, 'Workers × Days = constant, 5×12=60, 10×d=60, d=6', 1, '2026-03-25 11:50:15'),
(10, 'Quantitative Aptitude', 'Averages', 'Mean', 'Find the average of 10, 20, 30, 40, 50', '25', '30', '35', '40', '30', -1.20, 1.00, 'Sum = 150, count = 5, average = 30', 1, '2026-03-25 11:50:15'),
(11, 'Quantitative Aptitude', 'Averages', 'Weighted Average', 'A student scores 80 in Math (weight 3) and 90 in Science (weight 2). Find weighted average.', '82', '84', '86', '88', '84', 0.00, 1.00, '(80×3 + 90×2) / 5 = (240+180)/5 = 420/5 = 84', 1, '2026-03-25 11:50:15'),
(12, 'Quantitative Aptitude', 'Simple Interest', 'Interest Calculation', 'Find simple interest on $500 at 5% for 3 years', '$50', '$75', '$100', '$125', '$75', -0.80, 1.00, 'SI = P×R×T/100 = 500×5×3/100 = 75', 1, '2026-03-25 11:50:15'),
(13, 'Quantitative Aptitude', 'Geometry', 'Area of Circle', 'Find the area of a circle with radius 7 cm (π=22/7)', '154 cm²', '144 cm²', '164 cm²', '174 cm²', '154 cm²', 0.20, 1.00, 'Area = πr² = 22/7 × 7 × 7 = 154', 1, '2026-03-25 11:50:15'),
(14, 'Quantitative Aptitude', 'Geometry', 'Pythagoras Theorem', 'In a right triangle, legs are 3 and 4. Find hypotenuse.', '5', '6', '7', '8', '5', -1.00, 1.00, 'Hypotenuse = √(3²+4²)=√25=5', 1, '2026-03-25 11:50:15'),
(15, 'Quantitative Aptitude', 'Data Interpretation', 'Bar Graph', 'A bar graph shows sales: Jan=100, Feb=150, Mar=200. What is average monthly sales?', '100', '125', '150', '175', '150', 0.50, 1.00, 'Average = (100+150+200)/3 = 450/3 = 150', 1, '2026-03-25 11:50:15'),
(16, 'Quantitative Aptitude', 'Data Interpretation', 'Percentage from Graph', 'If total sales = 500, and product A sales = 125, what percentage is product A?', '20%', '25%', '30%', '35%', '25%', 0.00, 1.00, '(125/500) × 100 = 25%', 1, '2026-03-25 11:50:15'),
(17, 'Quantitative Aptitude', 'Advanced Math', 'Probability', 'What is probability of getting heads on a coin toss?', '1/3', '1/2', '2/3', '1/4', '1/2', -1.00, 1.00, 'Two outcomes, one favorable', 1, '2026-03-25 11:50:15'),
(18, 'Quantitative Aptitude', 'Advanced Math', 'Permutations', 'How many ways to arrange letters of \"CAT\"?', '3', '4', '5', '6', '6', 0.50, 1.00, '3! = 6 arrangements', 1, '2026-03-25 11:50:15'),
(19, 'Quantitative Aptitude', 'Advanced Math', 'Combinations', 'How many ways to choose 2 from 4 items?', '4', '6', '8', '12', '6', 0.80, 1.00, 'C(4,2) = 6', 1, '2026-03-25 11:50:15'),
(20, 'Logical Reasoning', 'Number Series', 'Pattern Recognition', 'Find the next number: 2, 4, 8, 16, ?', '24', '28', '30', '32', '32', -1.00, 1.00, 'Each number is multiplied by 2', 1, '2026-03-25 11:50:15'),
(21, 'Logical Reasoning', 'Number Series', 'Arithmetic Sequence', 'Find the next number: 5, 10, 15, 20, ?', '22', '23', '24', '25', '25', -1.20, 1.00, 'Add 5 each time', 1, '2026-03-25 11:50:15'),
(22, 'Logical Reasoning', 'Number Series', 'Geometric Sequence', 'Find the next number: 81, 27, 9, 3, ?', '0', '1', '2', '3', '1', -0.50, 1.00, 'Divide by 3 each time', 1, '2026-03-25 11:50:15'),
(23, 'Logical Reasoning', 'Number Series', 'Fibonacci Pattern', 'Find the next number: 1, 1, 2, 3, 5, ?', '6', '7', '8', '9', '8', 0.20, 1.00, 'Add previous two numbers: 3+5=8', 1, '2026-03-25 11:50:15'),
(24, 'Logical Reasoning', 'Blood Relations', 'Family Tree', 'A is the father of B. C is the mother of B. What is C to A?', 'Sister', 'Wife', 'Daughter', 'Mother', 'Wife', -0.50, 1.00, 'Parents of B: A is father, C is mother, so C is wife of A', 1, '2026-03-25 11:50:15'),
(25, 'Logical Reasoning', 'Blood Relations', 'Cousin Relations', 'Your mother\'s brother is your...', 'Uncle', 'Aunt', 'Cousin', 'Grandfather', 'Uncle', -0.20, 1.00, 'Mother\'s brother is maternal uncle', 1, '2026-03-25 11:50:15'),
(26, 'Logical Reasoning', 'Blood Relations', 'Grandparent Relation', 'Your father\'s father is your...', 'Uncle', 'Grandfather', 'Cousin', 'Brother', 'Grandfather', -0.80, 1.00, 'Father\'s father is paternal grandfather', 1, '2026-03-25 11:50:15'),
(27, 'Logical Reasoning', 'Coding-Decoding', 'Letter Coding', 'If CAT is coded as DBU, how is DOG coded?', 'EPH', 'EPI', 'EPJ', 'EPK', 'EPH', 0.50, 1.00, 'Each letter moves +1 position', 1, '2026-03-25 11:50:15'),
(28, 'Logical Reasoning', 'Coding-Decoding', 'Number Coding', 'If 123 = 6, 234 = 9, then 345 = ?', '10', '11', '12', '13', '12', 0.80, 1.00, 'Sum of digits: 1+2+3=6, 2+3+4=9, 3+4+5=12', 1, '2026-03-25 11:50:15'),
(29, 'Logical Reasoning', 'Direction Sense', 'North-South', 'A person walks 10m North, then 10m East, then 10m South. Where is he from start?', '5m East', '10m East', '10m West', 'Start point', '10m East', 0.00, 1.00, 'Net displacement: 10m East', 1, '2026-03-25 11:50:15'),
(30, 'Logical Reasoning', 'Direction Sense', 'Turns', 'If you face North and turn 90° clockwise, which direction do you face?', 'North', 'East', 'South', 'West', 'East', -1.00, 1.00, 'Clockwise from North = East', 1, '2026-03-25 11:50:15'),
(31, 'Logical Reasoning', 'Analogy', 'Word Analogy', 'Doctor : Hospital :: Teacher : ?', 'School', 'Office', 'Bank', 'Market', 'School', -0.80, 1.00, 'Doctor works in hospital, teacher works in school', 1, '2026-03-25 11:50:15'),
(32, 'Logical Reasoning', 'Analogy', 'Number Analogy', '3:9 :: 4:?', '12', '14', '16', '18', '16', 0.20, 1.00, '3²=9, 4²=16', 1, '2026-03-25 11:50:15'),
(33, 'Logical Reasoning', 'Odd One Out', 'Classification', 'Which is the odd one out? Apple, Orange, Banana, Carrot', 'Apple', 'Orange', 'Banana', 'Carrot', 'Carrot', -0.50, 1.00, 'Carrot is a vegetable, others are fruits', 1, '2026-03-25 11:50:15'),
(34, 'Logical Reasoning', 'Odd One Out', 'Number Classification', 'Which is odd? 2, 4, 6, 9', '2', '4', '6', '9', '9', -0.80, 1.00, '9 is odd, others are even', 1, '2026-03-25 11:50:15'),
(35, 'Logical Reasoning', 'Analytical Reasoning', 'Syllogisms', 'All cats are mammals. Some mammals are dogs. Which is true?', 'Some cats are dogs', 'All dogs are cats', 'Some mammals are cats', 'No conclusion', 'Some mammals are cats', 1.00, 1.00, 'From statements: cats are subset of mammals', 1, '2026-03-25 11:50:15'),
(36, 'Logical Reasoning', 'Analytical Reasoning', 'Logical Deduction', 'If it rains, ground gets wet. Ground is wet. What can we conclude?', 'It rained', 'It may have rained', 'It didn\'t rain', 'Ground is dry', 'It may have rained', 0.80, 1.00, 'Wet ground could be from other causes', 1, '2026-03-25 11:50:15'),
(37, 'Logical Reasoning', 'Analytical Reasoning', 'Assumptions', 'Statement: \"Use XYZ brand for better results.\" Assumption?', 'XYZ is cheap', 'Other brands are bad', 'Results can improve', 'Everyone uses XYZ', 'Results can improve', 0.50, 1.00, 'The claim implies results can improve', 1, '2026-03-25 11:50:15'),
(38, 'Verbal Ability', 'Synonyms', 'Vocabulary', 'What is the synonym of \"Happy\"?', 'Sad', 'Angry', 'Joyful', 'Tired', 'Joyful', -1.00, 1.00, 'Happy means joyful', 1, '2026-03-25 11:50:15'),
(39, 'Verbal Ability', 'Synonyms', 'Advanced Vocabulary', 'What is the synonym of \"Benevolent\"?', 'Cruel', 'Kind', 'Selfish', 'Greedy', 'Kind', 0.20, 1.00, 'Benevolent means kind and generous', 1, '2026-03-25 11:50:15'),
